29	const PROCESSING_FEE = 5;
30	const DEDUCTIBLE = 100;
31	const CAP_MULTIPLIER = 2;
32	
33	const BASE_PREMIUMS: Record<string, number> = {
34	  sword: 100,
35	  amulet: 60,
36	  staff: 80,
37	  potion: 40,
38	  rune: 25,
39	  moonstone: 25,
40	};
