51	const BLOCK_SIZE = 3;
52	const BLOCK_PRICE = 60;
53	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
54	
55	const LOYALTY_YEARS_THRESHOLD = 2;
56	const LOYALTY_DISCOUNT_RATE = 0.2;
57	const FIRST_INSURANCE_RATE = 0.1;
58	
59	const CURSE_SURCHARGE_RATE = 0.5;
60	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
61	const HIGH_ENCHANTMENT_THRESHOLD = 5;
62	const FOLLOWUP_DISCOUNT_RATE = 0.15;
63	
64	const unitPrice = (type: string): number => {
65	  const price = BASE_PREMIUMS[type];
66	  if (price === undefined) throw new Error(`Unknown item type: ${type}`);
67	  return price;
68	};
69	
70	const insuranceValue = (type: string): number => {
71	  const value = INSURANCE_VALUES[type];
72	  if (value === undefined) throw new Error(`Unknown item type: ${type}`);
73	  return value;
74	};
75	
76	const countsByType = (items: Item[]): Map<string, number> =>
77	  items.reduce(
78	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
79	    new Map<string, number>()
80	  );
81	
82	const groupTotal = (type: string, count: number): number =>
83	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
84	    ? BLOCK_PRICE
85	    : count * unitPrice(type);
86	
87	const sumBasePremiums = (items: Item[]): number =>
88	  Array.from(countsByType(items)).reduce(
89	    (total, [type, count]) => total + groupTotal(type, count),
90	    0
91	  );
92	
93	const itemSurcharges = (item: Item): number => {
94	  const base = unitPrice(item.type);
95	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
96	  const enchantment = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
97	    ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
98	    : 0;
99	  return curse + enchantment;
100	};
101	
102	const sumItemSurcharges = (items: Item[]): number =>
103	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
104	
105	const loyaltyDiscount = (
106	  basePremiums: number,
107	  customer: { yearsWithMHPCO: number }
108	): number =>
109	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
110	    ? basePremiums * LOYALTY_DISCOUNT_RATE
111	    : 0;
112	
113	const followupDiscount = (basePremiums: number, quoteIndex: number): number =>
114	  quoteIndex > 0 ? basePremiums * FOLLOWUP_DISCOUNT_RATE : 0;
115	
116	const quote = (
117	  { items }: QuoteStep,
118	  customer: { yearsWithMHPCO: number },
119	  quoteIndex: number
120	): QuoteResult => {
121	  const basePremiums = sumBasePremiums(items);
122	  const raw =
123	    basePremiums +
124	    sumItemSurcharges(items) -
125	    loyaltyDiscount(basePremiums, customer) +
126	    basePremiums * FIRST_INSURANCE_RATE -
127	    followupDiscount(basePremiums, quoteIndex) +
128	    PROCESSING_FEE;
129	  return { premium: Math.ceil(raw) };
130	};
