132	type Policy = {
133	  items: Item[];
134	  cap: number;
135	  remainingCap: number;
136	};
137	
138	const createPolicy = (items: Item[]): Policy => {
139	  const insuranceSum = items.reduce(
140	    (sum, item) => sum + insuranceValue(item.type),
141	    0
142	  );
143	  const cap = insuranceSum * CAP_MULTIPLIER;
144	  return { items, cap, remainingCap: cap };
145	};
146	
147	const damagePayout = (damage: Damage): number =>
148	  Math.max(0, damage.amount - DEDUCTIBLE);
149	
150	const claim = (step: ClaimStep, policies: Map<number, Policy>): ClaimResult => {
151	  const policy = policies.get(step.policy);
152	  if (!policy) throw new Error(`Policy ${step.policy} not found`);
153	  const desired = step.incident.damages.reduce(
154	    (sum, d) => sum + damagePayout(d),
155	    0
156	  );
157	  const payout = Math.min(desired, policy.remainingCap);
158	  policy.remainingCap -= payout;
159	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
160	};
