162	export const runScenario = (scenario: Scenario): ScenarioResult => {
163	  const policies = new Map<number, Policy>();
164	  let quoteIndex = 0;
165	  const results: StepResult[] = scenario.steps.map((step, index) => {
166	    if (step.op === "quote") {
167	      policies.set(index, createPolicy(step.items));
168	      const result = quote(step, scenario.customer, quoteIndex);
169	      quoteIndex++;
170	      return result;
171	    }
172	    return claim(step, policies);
173	  });
174	  return { results };
175	};
